SELECT "Primary endpoint"
FROM clinical_trials
WHERE "Cancer type" = 'Gastric/GEJ' AND "Type of combination" = 'ICI+Vaccine';

SELECT "Year", "Cancer type"
FROM clinical_trials
WHERE "Cancer type" = 'Bladder' AND "Class of ICI" = 'PD-L1' AND "Year" >= 2018;

SELECT "Year"
FROM clinical_trials
WHERE "Cancer type" = 'Small Cell Lung' AND "Class of ICI" = 'PD1' AND "Included in MA" = 'Yes';

SELECT "Year"
FROM clinical_trials
WHERE "Trial phase" = 'Phase 2' AND "Name of ICI" = 'Durvalumab' AND "Name of ICI" = 'Tremelimumab' AND "Cancer type" = 'Colorectal';

SELECT "Year"
FROM clinical_trials
WHERE "Trial phase" = 'Phase 3' AND "Name of ICI" = 'Durvalumab' AND "Name of ICI" = 'Tremelimumab' AND "Cancer type" = 'Small Cell Lung cancer' AND "Originial publication or Follow-up" = 'Follow-up';

SELECT "Year"
FROM clinical_trials
WHERE "Cancer type" = 'Colorectal' AND "Name of ICI" = 'Durvalumab' AND "Name of ICI" = 'Tremelimumab' AND "Trial phase" = 'Phase 2';

SELECT "Primary endpoint"
FROM clinical_trials
WHERE "Cancer type" = 'Prostate' AND "Monotherapy/combination" = 'Combination' AND "Treatment regimen" LIKE '%radiation%';

SELECT "Primary endpoint"
FROM clinical_trials
WHERE "Cancer type" = 'Prostate' AND "Monotherapy/combination" = 'Combination' AND "Treatment regimen" LIKE '%radiation therapy%';

SELECT "Treatment regimen"
FROM clinical_trials
WHERE "Trial phase" = 'Phase 3' AND "Monotherapy/combination" = 'Combination' AND "Cancer type" = 'Renal cell' AND "Name of ICI" IS NOT NULL;

SELECT "Treatment regimen"
FROM clinical_trials
WHERE "Trial phase" = 'Phase 3' AND "Monotherapy/combination" = 'Combination' AND "Cancer type" = 'Renal cell' AND "Name of ICI" IS NOT NULL;

SELECT "Primary endpoint"
FROM clinical_trials
WHERE "Cancer type" = 'Colorectal' AND "Type of combination" = 'ICI+Anti-VEGF' AND "Monotherapy/combination" = 'Combination';

SELECT "Year", "Type of combination"
FROM clinical_trials
WHERE "Cancer type" = 'Renal cell' AND "Type of combination" = 'ICI+Chemo';

SELECT "Treatment regimen"
FROM clinical_trials
WHERE "Trial phase" = 'Phase 3' AND "Monotherapy/combination" = 'Combination' AND "Cancer type" = 'Hepatocellular' AND "Class of ICI" = 'PD-L1';

SELECT "Treatment regimen"
FROM clinical_trials
WHERE "Trial phase" = 'Phase 3' AND "Cancer type" = 'Hepatocellular' AND "Monotherapy/combination" = 'Combination' AND "Class of ICI" = 'PD-L1';

SELECT "Primary endpoint"
FROM clinical_trials
WHERE "Cancer type" = 'Non-Small Cell Lung' AND "Type of combination" = 'ICI+Chemo';

SELECT "Primary endpoint"
FROM clinical_trials
WHERE "Cancer type" = 'Colorectal' AND "Monotherapy/combination" = 'Combination' AND "Type of combination" = 'ICI+Chemo+Anti-VEGF';
